sql:
SELECT name, reviews
FROM apps
ORDER BY reviews DESC;

SELECT AVG(rating) AS average_rating, reviews AS review_count
FROM apps
WHERE app_id = 1;

SELECT DISTINCT d.developer_name
FROM developers d
JOIN app_developers ad ON d.developer_id = ad.developer_id;

SELECT app_id
FROM apps
ORDER BY app_id;

SELECT MAX(review_count) AS highest_review_count
FROM (
  SELECT COUNT(review_id) AS review_count
  FROM reviews
  GROUP BY app_id
) AS review_counts;
